INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, "いらっしゃいませっ♪\nキャラバンコインを使って\n買い物ができますよっ！", 1.47, "クローチェ", 1, 1, 126401, -470.0, "2023/06/30 12:00:00", 2, 10001, 0.0, 2002, "2023/09/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, "素敵な品が揃ってるので\nたーっくさん買っていって\nくださいねっ♪", 2.15, "クローチェ", 1, 2, 126401, -470.0, "2023/06/30 12:00:00", 1, 10002, 0.0, 2002, "2023/09/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, "ショップへようこそ\nキャラバンコインはこちら\nで買い物に使えますよ", 0.0, "ライラエル", 1, 2, 126501, -470.0, "2023/06/30 12:00:00", 2, 10003, 0.0, 2002, "2023/09/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, "こちらのショップで\n買い物をして、素敵な\n旅を楽しんでくださいね", 0.0, "ライラエル", 1, 1, 126501, -470.0, "2023/06/30 12:00:00", 1, 10004, 0.0, 2002, "2023/09/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, "いらっしゃいませ\nキャラバンコインを使って\nお買い物ができますよ", 0.0, "リンド", 2, 2, 127702, -470.0, "2023/09/15 15:00:00", 2, 10005, 0.0, 2002, "2023/12/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, "ショップの掃除は完璧です\n姫さま直営のお店として\n当然のことですから", 0.0, "リンド", 2, 2, 127702, -470.0, "2023/09/15 15:00:00", 2, 10006, 0.0, 2002, "2023/12/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, "ショップへようこそ\nキャラバンコインと品物を\n交換できるんで、よければ", 0.0, "ヴルム", 2, 1, 127802, -470.0, "2023/09/15 15:00:00", 1, 10007, 0.0, 2002, "2023/12/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, "なんで店番なんか…\nま、やりますけど\n好きな品物をどうぞ", 6.5, "ヴルム", 2, 2, 127802, -470.0, "2023/09/15 15:00:00", 1, 10008, 0.0, 2002, "2023/12/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, "──いらっしゃいませ\n買い物しても、いいですよ\nキャラバンコインがあれば", 0.0, "アネモネ", 3, 2, 129602, -470.0, "2023/12/15 15:00:00", 1, 10009, 0.0, 2002, "2024/03/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, "──もっと笑顔がほしい？\nいくらコインを積まれても\n売れない物はありますから", 0.0, "アネモネ", 3, 2, 129602, -470.0, "2023/12/15 15:00:00", 1, 10010, 0.0, 2002, "2024/03/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, "ようこそおいでなんし\nキャラバンコインをこちら\nで交換して進ぜんしょう", 0.0, "ネフィ=ネラ", 3, 1, 129701, -470.0, "2023/12/15 15:00:00", 1, 10011, 0.0, 2002, "2024/03/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, "ところで、お前さまは\nいくらで贖えるのか喃？\n──フフ、冗談でありんす", 6.2, "ネフィ=ネラ", 3, 2, 129701, -470.0, "2023/12/15 15:00:00", 1, 10012, 0.0, 2002, "2024/03/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, "い、いらっしゃいませっ！\n…くっ…このあたくし様が\n店番なんて…屈辱ですわっ", 3.1, "カノン", 4, 3, 130301, -470.0, "2024/03/15 15:00:00", 5, 10013, 0.0, 2002, "2024/06/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, "あら、あたくしをご所望？\nお生憎様、そんな小銭では\n…買えちゃうんですの！？", 6.15, "カノン", 4, 3, 130301, -470.0, "2024/03/15 15:00:00", 2, 10014, 0.0, 2002, "2024/06/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, "いらっしゃいませ～♪\nきゃらばんこいん？を\n交換できるんだってー", 0.0, "ナーナ", 4, 2, 130401, -470.0, "2024/03/15 15:00:00", 2, 10015, 0.0, 2002, "2024/06/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, "甘いのくれたら、\nお礼にナーナの拾った\n松ぼっくりあげちゃうよ！", 3.35, "ナーナ", 4, 2, 130401, -470.0, "2024/03/15 15:00:00", 1, 10016, 0.0, 2002, "2024/06/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, "ショップへようこそ\nこの鳳凰が、皆さんに\n祝福を差し上げましょう", 0.0, "ホウオウ", 5, 1, 130502, -470.0, "2024/06/15 15:00:00", 1, 10017, 0.0, 2002, "2024/09/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, "ほーちゃんと呼ぶ権利は\n売っていませんよ？\n騎士さんへの、特別です！", 3.18, "ホウオウ", 5, 2, 130502, -470.0, "2024/06/15 15:00:00", 1, 10018, 0.0, 2002, "2024/09/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (3, "うﾞぇぇえんっ！まﾞだごの\n格好になっぢゃいまじだ！\n寄付をお願いじまず～っ！", 0.0, "ホウオウ", 5, 4, 130503, -470.0, "2024/06/15 15:00:00", 4, 10019, 0.0, 2002, "2024/09/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, "おっすー♪\nなんでも交換してけー\nカリザきゅん以外で", 4.9, "ネア", 5, 1, 123301, -470.0, "2024/06/15 15:00:00", 2, 10020, 0.0, 2002, "2024/09/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, "ところで、騎士きゅんは\nおいくら万ルピ？\nジョーダンぬ・き・で♡", 4.8, "ネア", 5, 1, 123301, -470.0, "2024/06/15 15:00:00", 2, 10021, 0.0, 2002, "2024/09/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, "ケッ、なんでオレ様が店番\nなんざ…って来んなキイロ\nオレは売りモンじゃねー！", 4.922, "カリザ", 6, 3, 133301, -470.0, "2024/09/15 15:00:00", 1, 10022, 0.0, 2002, "2024/12/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, "い、言わなきゃダメか？\n「…いらっしゃいませ…」\nクソッ、笑うんじゃねー！", 9.638, "カリザ", 6, 3, 133301, -470.0, "2024/09/15 15:00:00", 5, 10023, 0.0, 2002, "2024/12/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, "ショップへようこそ～\nネラさまの腹心…的な私が\n店番させていただきま～す", 2.88, "ミーア", 6, 1, 133401, -470.0, "2024/09/15 15:00:00", 2, 10024, 0.0, 2002, "2024/12/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, "私の抜け殻とか、\n需要ありますかね～…\nって冗談ですよ、冗談！", 4.818, "ミーア", 6, 5, 133401, -470.0, "2024/09/15 15:00:00", 1, 10025, 0.0, 2002, "2024/12/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, "へい、らっしゃい\nさ、騎士氏。冥土の土産は\nなにがいいですか？", 1.78, "グレイス", 7, 2, 133002, -470.0, "2024/12/15 15:00:00", 1, 10026, 0.0, 2002, "2025/03/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, "商品をお買い上げ毎に\nグレイスちゃんポイントを\n差し上げます。嘘ですが", 6.15, "グレイス", 7, 1, 133002, -470.0, "2024/12/15 15:00:00", 7, 10027, 0.0, 2002, "2025/03/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, "ようこそいらっしゃいませ\n…接客とは、このような\n振舞で宜しいでしょうか？", 4.28, "ヴァイオレット", 7, 6, 133102, -470.0, "2024/12/15 15:00:00", 2, 10028, 0.0, 2002, "2025/03/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, "じめじめした商品は\nございませんので\n安心してお買い求め下さい", 0.0, "ヴァイオレット", 7, 1, 133102, -470.0, "2024/12/15 15:00:00", 1, 10029, 0.0, 2002, "2025/03/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, "いらっしゃいましぇでしゅ\n何をお求めでしゅか？\nたこ焼きもありましゅよ！", 5.53, "ルルィ", 8, 2, 136902, -470.0, "2025/03/15 15:00:00", 1, 10030, 0.0, 2002, "2025/06/23 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, "そのコイン…ピカピカで、\n集めたくなっちゃいましゅ\nタコ釣られされちゃう～…", 6.05, "ルルィ", 8, 9, 136902, -470.0, "2025/03/15 15:00:00", 7, 10031, 0.0, 2002, "2025/06/23 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, "姫のご友人ならば\n礼儀を尽くすのが爺の務め\nさ、望みの物を言いたまえ", 0.0, "デュラン", 8, 2, 137001, -470.0, "2025/03/15 15:00:00", 1, 10032, 0.0, 2002, "2025/06/23 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, "キャラバンコインではなく\n首で支払って貰えんかのぅ\n…冗談であるぞ？", 0.0, "デュラン", 8, 2, 137001, -470.0, "2025/03/15 15:00:00", 1, 10033, 0.0, 2002, "2025/06/23 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, "おう\n好きなもん持ってきな", 0.0, "サツキ", 9, 2, 135902, -470.0, "2025/06/16 15:00:00", 2, 10034, 0.0, 2002, "2025/09/23 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, "宵越しの銭を持つような\n野暮いマネぁしくさんな\nツキが落ちてもしらねぇぜ", 4.935, "サツキ", 9, 1, 135902, -470.0, "2025/06/16 15:00:00", 6, 10035, 0.0, 2002, "2025/09/23 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, "ら、ら、らっしゃっせ…\nなんかほしいもん、ある？\nか、かき氷とか、ど…？", 7.441, "ユキノ", 9, 2, 135802, -470.0, "2025/06/16 15:00:00", 5, 10036, 0.0, 2002, "2025/09/23 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, "そ、そんな見ねぇで…\nあては、売りもんじゃ\nねぇよ…？", 0.0, "ユキノ", 9, 7, 135802, -470.0, "2025/06/16 15:00:00", 7, 10037, 0.0, 2002, "2025/09/23 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, "クルルをお求めですかっ？\nそれならお礼に、こちらの\n宝石もどうぞですよ～♪", 2.295, "クルル", 10, 2, 130901, -470.0, "2025/09/16 15:00:00", 2, 10038, 0.0, 2002, "2025/12/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, "はっ！　ヒーローさんから\nお代なんて頂けないです！\nどうぞどうぞ…え、ダメ？", 6.281, "クルル", 10, 1, 130901, -470.0, "2025/09/16 15:00:00", 6, 10039, 0.0, 2002, "2025/12/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, "よぅ！　今日の俺さまは\n門番じゃなく、店番だぜ\nメモピ～スフィア～てな！", 5.549, "ヴォルガーノ", 10, 2, 137701, -470.0, "2025/09/16 15:00:00", 1, 10040, 0.0, 2002, "2025/12/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, "…リマさんのブロマイド？\n買い取るに決まってらぁ！\nなんでも持ってけ泥棒っ！", 2.64, "ヴォルガーノ", 10, 3, 137701, -470.0, "2025/09/16 15:00:00", 6, 10041, 0.0, 2002, "2025/12/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, "こ、この格好は…ヴルムが\n集客効果があると言って…\n…本当でしょうか？", 7.642, "ライラエル", 11, 7, 132801, -470.0, "2025/12/15 15:00:00", 4, 10042, 0.0, 2002, "2026/03/23 11:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, "この我に店番させるとは…\n全て買わねば許さぬぞ\n我が国庫に貢献するが良い", 0.0, "ライラエル", 11, 1, 132802, -470.0, "2025/12/15 15:00:00", 1, 10043, 0.0, 2002, "2026/03/23 11:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, "アナライズっ！\n本日のオススメ商品は～…\nこちらですっ♪", 0.0, "クローチェ", 11, 1, 134502, -470.0, "2025/12/15 15:00:00", 1, 10044, 0.0, 2002, "2026/03/23 11:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, "ギガンティックローチェ、\nおひとついかがですかっ？\n格納庫用意して下さいねっ", 3.72, "クローチェ", 11, 2, 134501, -470.0, "2025/12/15 15:00:00", 1, 10045, 0.0, 2002, "2026/03/23 11:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, "番頭も、飯事の如き営み\nなれば。愛らしき稚児らで\n千客万来といきませぬか喃", 4.991, "ネフィ＝ネラ", 12, 2, 138201, -470.0, "2026/03/16 12:00:00", 1, 10046, 0.0, 2002, "2026/06/22 11:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, "国を営むに金子は必須也…\nどうか御恵みくだしゃんせ\n誠心を以て報恩致しまする", 3.877, "ネフィ＝ネラ", 12, 1, 138201, -470.0, "2026/03/16 12:00:00", 4, 10047, 0.0, 2002, "2026/06/22 11:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, "あぅっ…！　天井が低くて\n頭をぶつけてしまって…\nわたしが、大きいだけ…？", 1.71, "アラクネ", 12, 4, 136001, -470.0, "2026/03/16 12:00:00", 6, 10048, 0.0, 2002, "2026/06/22 11:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, "いらっしゃいませ騎士さま\nくつろいでいって下さいね\nもし叶うなら…永遠に…", 5.32, "アラクネ", 12, 5, 136001, -470.0, "2026/03/16 12:00:00", 2, 10049, 0.0, 2002, "2026/06/22 11:59:59");
